public float floatValue() {
    if (denominator.floatValue() == 0.0f) {
        throw new ArithmeticException("Division by zero");
    }
    BigDecimal numeratorDecimal = new BigDecimal(numerator.toString());
    BigDecimal denominatorDecimal = new BigDecimal(denominator.toString());
    BigDecimal result = numeratorDecimal.divide(denominatorDecimal, 8, BigDecimal.ROUND_HALF_UP);
    return result.floatValue();
}

public double doubleValue() {
    java.math.BigDecimal numer = new java.math.BigDecimal(numerator);
    java.math.BigDecimal denom = new java.math.BigDecimal(denominator);
    return numer.divide(denom, java.math.MathContext.DECIMAL128).doubleValue();
}

